{
  "title": "Pengantar Python untuk Pemula",
  "description": "Kursus ini dirancang untuk memperkenalkan pemrograman Python kepada pemula muda di kawasan ASEAN. Dengan pendekatan berbasis teks dan aktivitas ringan, peserta akan belajar dasar-dasar Python dan cara menerapkannya dalam proyek sederhana.",
  "modules": [
    {
      "id": "module_1",
      "title": "Pengenalan Python",
      "description": "Mempelajari apa itu Python, sejarahnya, dan mengapa Python menjadi pilihan populer untuk pemrograman. Peserta akan memahami cara menginstal Python dan menyiapkan lingkungan pengembangan."
    },
    {
      "id": "module_2",
      "title": "Dasar-Dasar Sintaks Python",
      "description": "Memahami sintaks dasar Python, termasuk variabel, tipe data, dan operator. Peserta akan melakukan latihan ringan untuk menulis dan menjalankan kode Python sederhana."
    },
    {
      "id": "module_3",
      "title": "Kontrol Alur dan Fungsi",
      "description": "Mempelajari struktur kontrol seperti pernyataan if, loop, dan cara mendefinisikan fungsi. Aktivitas praktis akan membantu peserta menerapkan konsep ini dalam program mereka."
    },
    {
      "id": "module_4",
      "title": "Proyek Akhir: Membuat Aplikasi Sederhana",
      "description": "Peserta akan menerapkan semua yang telah dipelajari untuk membuat aplikasi sederhana menggunakan Python. Proyek ini akan memfasilitasi pemahaman praktis dan kreativitas dalam pemrograman."
    }
  ]
}
